create table if not exists ac_incidents (id uuid primary key default uuid_generate_v4(), title text, severity text, region text, person_id uuid references ac_people(id), client text, root_cause text, corrective_action text, owner text, status text default 'open', due_date date, created_at timestamptz default now());
create table if not exists ac_documents (id uuid primary key default uuid_generate_v4(), person_id uuid references ac_people(id), document_type text, status text default 'missing', expires_at date, file_url text, verified_by text, verified_at timestamptz);
create table if not exists ac_performance_reviews (id uuid primary key default uuid_generate_v4(), person_id uuid references ac_people(id), period text, reliability int, behavior int, client_satisfaction int, mission_success int, compliance int, incentive_decision text, corrective_action text, created_at timestamptz default now());
